module top_module(
  // inputs:
  rst,
  reset,

  // outputs:
  count
);// inputs
  input rst;
  input reset;

  // outputs
  output reg [3:0] count;

  // counter logic
  always @(posedge rst, negedge reset) begin
    if (!reset) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
